```python
# crystal_integration_adapter.py - Bridge between PDF-spec Crystal AI and existing modules

import time
import uuid
from typing import Dict, List, Optional, Any, Tuple
from dataclasses import dataclass

# Import the proper Crystal AI implementation
from crystal_ai_system import (
    Crystal, CrystalMemory, CrystalLevel, FacetPoint, CrystalFacet, CrystalAI
)

class CrystalAdapter:
    """Adapter to make PDF-spec crystals work with existing modules"""

    def __init__(self, pdf_crystal: Crystal):
        self.pdf_crystal = pdf_crystal
        self._cached_facet_map = None

    @property
    def id(self) -> str:
        return self.pdf_crystal.id

    @property 
    def concept(self) -> str:
        return self.pdf_crystal.concept

    @property
    def content(self) -> str:
        # Return definition facet as primary content
        definition = self.pdf_crystal.get_facet_content("definition")
        return definition if definition else ""

    @property
    def connections(self) -> Dict[str, int]:
        return self.pdf_crystal.connections

    @property
    def usage_count(self) -> int:
        return self.pdf_crystal.usage_count

    @property
    def last_accessed(self) -> float:
        return self.pdf_crystal.last_accessed

    @property
    def evolution_level(self) -> int:
        return self.pdf_crystal.level.value  # Convert enum to int

    @property
    def total_attraction_score(self) -> float:
        # Calculate attraction from crystal resonance
        total_resonance = sum(facet.get_total_resonance() for facet in self.pdf_crystal.facets.values())
        return total_resonance

    @property
    def facets(self) -> Dict[int, 'FacetAdapter']:
        """Return facets in format expected by existing modules"""
        if self._cached_facet_map is None:
            self._cached_facet_map = {}
            for facet_id, pdf_facet in self.pdf_crystal.facets.items():
                self._cached_facet_map[facet_id] = FacetAdapter(pdf_facet)
        return self._cached_facet_map

    def touch(self):
        """Record usage"""
        self.pdf_crystal.touch()

    def strengthen(self, other_id: str, weight: int = 1):
        """Strengthen connection to another crystal"""
        self.pdf_crystal.strengthen_connection(other_id, weight)

    def set_facet(self, role: str, text: str, context: str = "") -> bool:
        """Set facet content (compatible with existing interface)"""
        return self.pdf_crystal.set_facet_content(role, text)

    def get_facet(self, role: str) -> Optional[str]:
        """Get facet content"""
        return self.pdf_crystal.get_facet_content(role)

    def should_evolve(self) -> bool:
        """Check if crystal should evolve"""
        return self.pdf_crystal.check_evolution_criteria()

    def evolve(self) -> bool:
        """Attempt evolution"""
        return self.pdf_crystal.evolve()

class FacetAdapter:
    """Adapter for facets to work with existing modules"""

    def __init__(self, pdf_facet: CrystalFacet):
        self.pdf_facet = pdf_facet
        self.attraction_points = self._create_attraction_points()

    @property
    def content(self) -> str:
        return self.pdf_facet.description

    def _create_attraction_points(self) -> Dict[int, 'AttractionPointAdapter']:
        """Convert PDF facet points to attraction points format"""
        points = {}
        for i, (point_name, point) in enumerate(self.pdf_facet.points.items()):
            points[i] = AttractionPointAdapter(point, point_name)
        return points

    def update_content_with_scarring(self, new_content: str, evolution_level: int, context: str = ""):
        """Update content (compatible interface)"""
        self.pdf_facet.update_content(new_content)

class AttractionPointAdapter:
    """Adapter for attraction points"""

    def __init__(self, pdf_point: FacetPoint, point_name: str):
        self.pdf_point = pdf_point
        self.point_name = point_name
        self.dimensions = self._map_to_dimensions()
        self.total_score = abs(pdf_point.value)

    def _map_to_dimensions(self) -> Dict[str, float]:
        """Map PDF point types to attraction dimensions"""
        mapping = {
            "emotional": "emotional_resonance",
            "polarity": "practical_utility",  # Polarity affects utility
            "associative": "network_centrality",
            "abstract": "conceptual_depth", 
            "temporal": "temporal_significance",
            "cognitive": "personal_relevance",  # Cognitive depth affects personal relevance
            "recursive": "conceptual_depth",
            "nexus": "network_centrality"
        }

        dimension_name = mapping.get(self.point_name, "conceptual_depth")
        return {dimension_name: abs(self.pdf_point.value)}

class MemoryAdapter:
    """Adapter to make CrystalMemory work with existing modules"""

    def __init__(self, crystal_memory: CrystalMemory):
        self.crystal_memory = crystal_memory
        self.path = crystal_memory.path
        self.autosave = crystal_memory.autosave
        self._crystal_adapters = {}

    @property
    def crystals(self) -> Dict[str, CrystalAdapter]:
        """Return crystals as adapters"""
        # Update adapter cache
        for crystal_id, pdf_crystal in self.crystal_memory.crystals.items():
            if crystal_id not in self._crystal_adapters:
                self._crystal_adapters[crystal_id] = CrystalAdapter(pdf_crystal)

        # Remove adapters for deleted crystals
        to_remove = []
        for crystal_id in self._crystal_adapters:
            if crystal_id not in self.crystal_memory.crystals:
                to_remove.append(crystal_id)

        for crystal_id in to_remove:
            del self._crystal_adapters[crystal_id]

        return self._crystal_adapters

    def get(self, crystal_id: str) -> Optional[CrystalAdapter]:
        """Get crystal adapter"""
        pdf_crystal = self.crystal_memory.get_crystal(crystal_id)
        if pdf_crystal:
            if crystal_id not in self._crystal_adapters:
                self._crystal_adapters[crystal_id] = CrystalAdapter(pdf_crystal)
            return self._crystal_adapters[crystal_id]
        return None

    def ensure_concept(self, concept: str, content: str = "", level: int = 1, context: str = "") -> str:
        """Ensure concept exists"""
        crystal_level = CrystalLevel(level)
        return self.crystal_memory.ensure_crystal(concept, content, crystal_level)

    def link(self, crystal_id1: str, crystal_id2: str, weight: int = 1):
        """Link crystals"""
        self.crystal_memory.link_crystals(crystal_id1, crystal_id2, weight)

    def maybe_promote(self, crystal_id: str):
        """Attempt to evolve crystal"""
        crystal = self.crystal_memory.get_crystal(crystal_id)
        if crystal:
            crystal.evolve()

    def save(self, path: str = None):
        """Save memory"""
        self.crystal_memory.save()

    @classmethod
    def load(cls, path: str) -> 'MemoryAdapter':
        """Load memory"""
        crystal_memory = CrystalMemory(path)
        return cls(crystal_memory)

class IntegratedCrystalSystem:
    """Complete integrated system using PDF-spec crystals with existing module interfaces"""

    def __init__(self, memory_path: str = "crystal_memory.json"):
        # Initialize PDF-spec crystal memory
        self.crystal_memory = CrystalMemory(memory_path)
        self.memory = MemoryAdapter(self.crystal_memory)

        # Initialize existing modules with adapted memory
        self._initialize_modules()

    def _initialize_modules(self):
        """Initialize existing modules with crystal adapters"""
        try:
            # Crystal Binding Module
            from crystal_binding_module import CrystalBindingController
            self.binding_controller = CrystalBindingController(self.memory)
            print("✓ Crystal binding module initialized")
        except ImportError as e:
            print(f"Warning: Crystal binding module not available: {e}")
            self.binding_controller = None

        try:
            # Temporal Continuity System
            from temporal_continuity_system import TemporalContinuityController
            if self.binding_controller:
                self.temporal_controller = TemporalContinuityController(self.memory, self.binding_controller)
                print("✓ Temporal continuity module initialized")
            else:
                self.temporal_controller = None
        except ImportError as e:
            print(f"Warning: Temporal continuity module not available: {e}")
            self.temporal_controller = None

        try:
            # Pathway Association System
            from pathway_association_system import PathwayAssociationController
            if self.temporal_controller:
                self.association_controller = PathwayAssociationController(self.temporal_controller)
                print("✓ Pathway association module initialized")
            else:
                self.association_controller = None
        except ImportError as e:
            print(f"Warning: Pathway association module not available: {e}")
            self.association_controller = None

        try:
            # Conversational Engine
            from chatbot_core_v3_updated import EnhancedFractalCrystalBot
            # Pass full system instead of memory
            self.conversational_bot = EnhancedFractalCrystalBot(self)
            print("✓ Conversational engine initialized")
        except ImportError as e:
            print(f"Warning: Conversational engine not available: {e}")
            self.conversational_bot = None

    # ... rest of the file unchanged ...
```

